sourcesContent":[".wuwa-opening {\r\n  margin: 0;\r\n  padding: 0;\r\n  font-family: 'Segoe UI', 'Microsoft YaHei', sans-serif;\r\n  overflow: hidden;\r\n  color: #334155;\r\n  width: 100%;\r\n  display: flex;\r\n  justify-content: center;\r\n  box-sizing: border-box;\r\n}\r\n\r\n.wuwa-opening--expanded {\r\n  position: fixed;\r\n  inset: 0;\r\n  z-index: 999998;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  padding: 12px;\r\n  background: rgba(15, 23, 42, 0.88);\r\n  backdrop-filter: blur(6px);\r\n  box-sizing: border-box;\r\n  container-type: size;\r\n}\r\n\r\n.wuwa-opening--expanded .wuwa-shell {\r\n  width: min(100cqw, 100cqh, 720px);\r\n  max-width: none;\r\n  height: auto;\r\n}\r\n\r\n.wuwa-shell {\r\n  position: relative;\r\n  width: 100%;\r\n  max-width: 720px;\r\n  aspect-ratio: 1 / 1;\r\n  box-sizing: border-box;\r\n}\r\n\r\n.wuwa-fullscreen-btn {\r\n  position: absolute;\r\n  top: 12px;\r\n  right: 12px;\r\n  z-index: 30;\r\n  display: inline-flex;\r\n  align-items: center;\r\n  gap: 6px;\r\n  height: 34px;\r\n  padding: 0 12px;\r\n  border: 1px solid rgba(56, 189, 248, 0.35);\r\n  border-radius: 10px;\r\n  background: rgba(255, 255, 255, 0.92);\r\n  color: #0369a1;\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  cursor: pointer;\r\n  box-shadow: 0 4px 14px rgba(15, 23, 42, 0.12);\r\n  transition: all 0.2s ease;\r\n}\r\n\r\n.wuwa-fullscreen-btn:hover,\r\n.wuwa-fullscreen-btn--active {\r\n  border-color: #38bdf8;\r\n  color: #0284c7;\r\n  background: #e0f2fe;\r\n}\r\n\r\n.wuwa-fullscreen-btn__icon {\r\n  width: 14px;\r\n  height: 14px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.wuwa-panel {\r\n  background-color: white;\r\n  border-radius: 20px;\r\n  padding: 0;\r\n  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.25);\r\n  width: 100%;\r\n  height: 100%;\r\n  box-sizing: border-box;\r\n  transition: all 0.3s ease;\r\n  position: relative;\r\n  overflow: hidden;\r\n  border: 1.2px solid #eee;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.wuwa-panel__scroll {\r\n  position: relative;\r\n  z-index: 5;\r\n  flex: 1;\r\n  min-height: 0;\r\n  overflow-x: hidden;\r\n  overflow-y: auto;\r\n  padding: 48px 20px 16px;\r\n  box-sizing: border-box;\r\n  scrollbar-width: thin;\r\n  scrollbar-color: rgba(56, 189, 248, 0.45) transparent;\r\n}\r\n\r\n.wuwa-panel__scroll::-webkit-scrollbar {\r\n  width: 5px;\r\n}\r\n\r\n.wuwa-panel__scroll::-webkit-scrollbar-thumb {\r\n  background: rgba(56, 189, 248, 0.45);\r\n  border-radius: 999px;\r\n}\r\n\r\n.wuwa-logo-container {\r\n  display: flex;\r\n  justify-content: center;\r\n  align-items: center;\r\n  width: 100%;\r\n  margin-bottom: 16px;\r\n  position: relative;\r\n  z-index: 10;\r\n  padding-top: 8px;\r\n}\r\n\r\n.wuwa-logo {\r\n  max-width: 180px;\r\n  height: auto;\r\n  filter: drop-shadow(0 0 12px rgba(56, 189, 248, 0.5));\r\n  will-change: transform, opacity;\r\n}\r\n\r\n.wuwa-logo-container--intro {\r\n  animation: logoIntro 1.2s cubic-bezier(0.22, 1, 0.36, 1) forwards;\r\n}\r\n\r\n@keyframes logoIntro {\r\n  0% {\r\n    transform: scale(1.4) translateY(150px);\r\n    opacity: 0;\r\n  }\r\n  40% {\r\n    opacity: 1;\r\n  }\r\n  100% {\r\n    transform: scale(1) translateY(0);\r\n    opacity: 1;\r\n  }\r\n}\r\n\r\n@keyframes fadeInUp {\r\n  from {\r\n    opacity: 0;\r\n    transform: translateY(20px);\r\n  }\r\n  to {\r\n    opacity: 1;\r\n    transform: translateY(0);\r\n  }\r\n}\r\n\r\n@keyframes heartbeat {\r\n  0% {\r\n    transform: scale(1);\r\n    box-shadow: 0 4px 15px rgba(2, 132, 199, 0.3);\r\n  }\r\n  50% {\r\n    transform: scale(1.03);\r\n    box-shadow: 0 0 25px rgba(56, 189, 248, 0.6);\r\n  }\r\n  100% {\r\n    transform: scale(1);\r\n    box-shadow: 0 4px 15px rgba(2, 132, 199, 0.3);\r\n  }\r\n}\r\n\r\n.wuwa-grid {\r\n  display: grid;\r\n  grid-template-columns: 1fr;\r\n  gap: 16px;\r\n  opacity: 0;\r\n  position: relative;\r\n  z-index: 5;\r\n}\r\n\r\n.wuwa-grid--intro {\r\n  animation: fadeInUp 0.8s ease 0.6s forwards;\r\n}\r\