import { createScriptIdDiv, createScriptIdIframe, teleportStyle } from '@util/script';
import { uuidv4 } from './common';
/** 脚本 iframe 内须用主页面 jQuery 才能找到 #chat / .mes */
function host$() {
    try {
        const w = window.top && window.top !== window
            ? window.top
            : window.parent && window.parent !== window
                ? window.parent
                : window;
        const jq = w.$;
        if (jq)
            return jq;
    }
    catch {
        /* cross-origin */
    }
    return $;
}
function hostDocument() {
    try {
        if (window.top && window.top !== window)
            return window.top.document;
    }
    catch {
        /* cross-origin */
    }
    try {
        if (window.parent && window.parent !== window)
            return window.parent.document;
    }
    catch {
        /* cross-origin */
    }
    return document;
}
const MES_TEXT_HIDE_CLASS = 'th-mes-text-hidden';
function ensureMesTextHideStyle() {
    const $doc = host$()(hostDocument());
    if ($doc.find(`head > style#${MES_TEXT_HIDE_CLASS}-style`).length)
        return;
    host$()(`<style id="${MES_TEXT_HIDE_CLASS}-style">.${MES_TEXT_HIDE_CLASS}{display:none!important;}</style>`).appendTo($doc.find('head'));
}
function hideMesText($mes_text) {
    ensureMesTextHideStyle();
    $mes_text.addClass(MES_TEXT_HIDE_CLASS);
}
function showMesText($mes_text) {
    $mes_text.removeClass(MES_TEXT_HIDE_CLASS);
}
/**
 * 将组件作为流式楼层界面挂载到酒馆各个楼层, 替换掉酒馆原生的楼层正文显示.
 *
 * 方案是隐藏酒馆原来的楼层文本, 而在它下方插入一个类名有 `mes_streaming` 的 DOM:
 *   - `options.host==='iframe'` 则插入的是 iframe, 其内 contentDocument.body 作为组件的挂载点
 *     - 样式将与酒馆原生界面隔离
 *     - 组件内可以使用 tailwindcss
 *   - `options.host==='div'` 则插入的是 div, 它直接作为组件的挂载点
 *     - 将会继承酒馆样式
 *     - 禁止使用 mes_text 类名, 它会让酒馆的编辑楼层功能不可用
 *     - 组件内不能使用 tailwindcss, 因为会影响酒馆其他部分的样式
 *     - 你也许会用到 `@types/function/displayed_message.d.ts` 中的 `formatAsDisplayedMessage` 来格式化消息内容, 并用 `.replaceAll('mes_text', 'mes_streaming')` 来为格式化后内容适配样式
 *
 * @param creator 创建流式界面的组件, 函数内可以用 `.use` 安装依赖或执行其他逻辑
 * @param options 可选选项
 *   - `host`: 宿主, 默认为 `'iframe'`, 因为 `'iframe'` 能隔离样式, 更方便做复杂界面
 *   - `filter`: 楼层过滤器. 如果设置, 则只有符合条件的楼层才会被挂载流式楼层界面
 *   - `prefix`: 组件的唯一标识符, 默认随机生成一个. 函数产生的流式楼层界面会共享这个 `prefix`, 并将 `host` DOM 的 id 设置成 `${prefix}-${message_id}`.
 * @returns 卸载流式楼层界面的函数
 */
export function mountStreamingMessages(creator, options = {}) {
    const { host = 'iframe', filter, prefix = uuidv4() } = options;
    const states = new Map();
    let has_stoped = false;
    const resolveChatUpperBound = () => {
        try {
            const last_mesid = Number(host$()('#chat > .mes').last().attr('mesid'));
            if (!Number.isNaN(last_mesid))
                return last_mesid + 1;
        }
        catch {
            /* ignore */
        }
        try {
            const len = SillyTavern?.chat?.length;
            if (typeof len === 'number' && len > 0)
                return len;
        }
        catch {
            /* ignore */
        }
        return Number.MAX_SAFE_INTEGER;
    };
    const destroyIfInvalid = (message_id) => {
        const min_message_id = Number(host$()('#chat > .mes').first().attr('mesid'));
        const upper = resolveChatUpperBound();
        if (Number.isNaN(min_message_id) || !_.inRange(message_id, min_message_id, upper)) {
            states.get(message_id)?.destroy();
            return true;
        }
        return false;
    };
    const destroyAllInvalid = () => {
        states.keys().forEach(message_id => destroyIfInvalid(message_id));
    };
    const renderOneMessage = async (message_id, stream_message) => {
        if (has_stoped) {
            return;
        }
        if (destroyIfInvalid(message_id)) {
            return;
        }
        const message = stream_message ?? getChatMessages(message_id)[0].message ?? '';
        if (filter && !filter(message_id, message)) {
            states.get(message_id)?.destroy();
            return;
        }
        const $message_element = host$()(`.mes[mesid='${message_id}']`);
        const $mes_text = $message_element.find('.mes_text');
        hideMesText($mes_text);
        $message_element.find('.TH-streaming').addClass(MES_TEXT_HIDE_CLASS);
        let $host = $message_element.find(`#${prefix}-${message_id}`);
        if ($host.length > 0) {
            const state = states.get(message_id);
            if (state) {
                state.data.message = message;
                state.data.during_streaming = Boolean(stream_message);
                return;
            }
        }
        states.get(message_id)?.destroy();
        $host.remove();
        let $mes_streaming = $message_element.find('.mes_streaming');
        if ($mes_streaming.length === 0) {
            $mes_streaming = host$()('<div class="mes_streaming">')
                .css({
                'font-weight': '500',
                'line-height': 'calc(var(--mainFontSize) + .5rem)',
                'max-width': '100%',
                'overflow-wrap': 'anywhere',
                padding: 'calc(var(--mainFontSize) * 0.8) 0 0 0',
            })
                .insertAfter($mes_text);
        }
        $host = (host === 'iframe' ? createScriptIdIframe().addClass('w-full') : createScriptIdDiv())
            .attr('id', `${prefix}-${message_id}`)
            .appendTo($mes_streaming);
        const data = reactive({
            prefix,
            host_id: `${prefix}-${message_id}`,
            message_id,
            message,
            during_streaming: Boolean(stream_message),
        });
        const app = creator().provide('streaming_message_context', data);
        if (host === 'iframe') {
            $host.on('load', function () {
                teleportStyle(this.contentDocument.head);
                app.mount(this.contentDocument.body);
            });
        }
        else {
            app.mount($host[0]);
        }
        const observer = new MutationObserver(() => {
            const $edit_textarea = host$()('#chat').find('#curEditTextarea');
            if ($edit_textarea.parent().is($mes_text)) {
                showMesText($mes_text);
                $host.addClass(MES_TEXT_HIDE_CLASS);
            }
            else if ($edit_textarea.length === 0) {
                hideMesText($mes_text);
                $message_element.find('.TH-streaming').addClass(MES_TEXT_HIDE_CLASS);
                $host.removeClass(MES_TEXT_HIDE_CLASS);
            }
        });
        observer.observe($mes_text[0], { childList: true });
        states.set(message_id, {
            app,
            data,
            destroy: () => {
                const $th_streaming = $message_element.find('.TH-streaming');
                if ($th_streaming.length > 0) {
                    $th_streaming.removeClass(MES_TEXT_HIDE_CLASS);
                }
                else {
                    showMesText($mes_text);
                }
                app.unmount();
                $host.remove();
                if ($mes_streaming.children().length === 0) {
                    $mes_streaming.remove();
                }
                observer.disconnect();
                states.delete(message_id);
            },
        });
    };
    const renderAllMessage = async (options = {}) => {
        if (has_stoped) {
            return;
        }
        if (options.destroy_all) {
            states.forEach(({ destroy }) => destroy());
        }
        else {
            destroyAllInvalid();
        }
        await Promise.all(host$()('#chat')
            .children('.mes')
            .map(async (_index, node) => {
            const message_id = Number(host$()(node).attr('mesid') ?? 'NaN');
            if (!isNaN(message_id)) {
                await renderOneMessage(message_id);
                if (options.trigger_event) {
                    eventEmit(tavern_events.CHARACTER_MESSAGE_RENDERED, message_id, 'rerender');
                }
            }
        }));
    };
    const stop_list = [];
    const scopedEventOn = (event, listener, first) => {
        stop_list.push(first ? eventMakeFirst(event, errorCatched(listener)).stop : eventOn(event, errorCatched(listener)).stop);
    };
    scopedEventOn('chatLoaded', () => {
        renderAllMessage({ destroy_all: true });
    });
    scopedEventOn(tavern_events.CHARACTER_MESSAGE_RENDERED, message_id => {
        destroyAllInvalid();
        renderOneMessage(message_id);
    }, true);
    [tavern_events.MESSAGE_EDITED, tavern_events.MESSAGE_DELETED].forEach(event => scopedEventOn(event, message_id => {
        destroyAllInvalid();
        states.get(message_id)?.destroy();
        renderOneMessage(message_id);
    }));
    [tavern_events.MORE_MESSAGES_LOADED, tavern_events.MESSAGE_DELETED].forEach(event => scopedEventOn(event, () => setTimeout(errorCatched(renderAllMessage), 1000)));
    scopedEventOn(tavern_events.STREAM_TOKEN_RECEIVED, message => {
        renderOneMessage(Number(host$()('#chat').children('.mes.last_mes').attr('mesid')), message);
    });
    if (host === 'div') {
        stop_list.push(teleportStyle().destroy);
    }
    renderAllMessage({ trigger_event: true });
    return {
        unmount: () => {
            const $th_streaming = host$()('#chat').find('.TH-streaming');
            if ($th_streaming.length > 0) {
                $th_streaming.removeClass(MES_TEXT_HIDE_CLASS);
            }
            else {
                host$()('#chat').find('.mes_text').removeClass(MES_TEXT_HIDE_CLASS);
            }
            states.forEach(({ destroy }) => destroy());
            stop_list.forEach(stop => stop());
            has_stoped = true;
        },
    };
}
