import { mountStreamingMessages } from '@util/streaming';
import { exposeWuwaConsoleTools } from '../../shared/wuwaConsoleTools';
import { publishWuwaAssetsBase } from '../../shared/wuwaMedia';
import { ensureWuWaSharedRegistered } from '../../shared/register';
import App from './App.vue';
import { chatHasWuwaGameStarted, shouldShowOpeningPanel } from './openingLogic';
$(async () => {
    publishWuwaAssetsBase();
    ensureWuWaSharedRegistered();
    exposeWuwaConsoleTools();
    await Promise.race([
        waitGlobalInitialized('Mvu'),
        new Promise(resolve => setTimeout(resolve, 5000)),
    ]);
    let dismissOpening = null;
    function mountOpeningPanel() {
        if (dismissOpening || chatHasWuwaGameStarted())
            return;
        const { unmount } = mountStreamingMessages(() => createApp(App), {
            host: 'iframe',
            prefix: 'wuwa-opening',
            filter: (message_id, message) => message_id === 0 && shouldShowOpeningPanel(message),
        });
        dismissOpening = () => {
            unmount();
            dismissOpening = null;
        };
    }
    function tryDismissOpening() {
        if (chatHasWuwaGameStarted())
            dismissOpening?.();
    }
    mountOpeningPanel();
    console.info('[鸣潮开场] 流式楼层界面已挂载，匹配标记 [角色创建与故事开场]');
    const opening_dismiss_events = [
        tavern_events.CHARACTER_MESSAGE_RENDERED,
        tavern_events.MESSAGE_RECEIVED,
        tavern_events.GENERATION_ENDED,
        tavern_events.CHAT_CHANGED,
    ];
    for (const event of opening_dismiss_events) {
        eventOn(event, tryDismissOpening);
    }
    eventOn(tavern_events.CHAT_CHANGED, () => {
        if (!dismissOpening && !chatHasWuwaGameStarted())
            mountOpeningPanel();
    });
    $(window).on('pagehide', () => dismissOpening?.());
});
